import{c as t,Q as i,j as a,m as o}from"./chunks/framework.CdiUUa3G.js";const p=JSON.parse('{"title":"ADR-016 — All external assets resolved at build time","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-016.md","filePath":"adr/ADR-016.md"}'),s={name:"adr/ADR-016.md"};function r(n,e,l,d,c,m){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="adr-016-—-all-external-assets-resolved-at-build-time" tabindex="-1">ADR-016 — All external assets resolved at build time <a class="header-anchor" href="#adr-016-—-all-external-assets-resolved-at-build-time" aria-label="Permalink to &quot;ADR-016 — All external assets resolved at build time&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-04-28 TA anchor · §stack · §constraints</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The application currently depends on several external URLs at runtime: NASA Images API for mission imagery, Three.js GitHub CDN for planet textures, Wikimedia Commons for agency logos, and Google Fonts for typography. These dependencies are brittle (URLs change, services go down, rate limits apply) and prevent true offline use. At production scale with millions of users, external runtime dependencies are a reliability and performance risk.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>All external assets are resolved at build time by GitHub Actions scripts. Nothing in the production bundle fetches from a third-party URL at runtime. Assets are served from the application&#39;s own host.</p><p>The asset types and their build-time resolution:</p><ul><li><strong>Google Fonts</strong> — downloaded via <code>scripts/fetch-assets.ts</code>, committed to <code>static/fonts/</code> <em>(implemented in Slice 1)</em></li><li><strong>Planet textures</strong> — downloaded from Solar System Scope (CC BY 4.0; the originally-named Three.js r128 source did not actually carry the 2k_*.jpg set), written to <code>static/textures/</code> <em>(implemented in Slice 3 / 3a-2)</em></li><li><strong>Agency logos</strong> — downloaded from Wikimedia Commons during build, written to <code>static/logos/</code> <em>(scheduled for Slice 4 with the mission library)</em></li><li><strong>Mission imagery</strong> — fetched at build into <code>static/images/missions/[id]/</code>. <strong>Source priority</strong> (agency-first, NASA as fallback library) is locked in <strong>ADR-046</strong>; ADR-016 only requires build-time bundling, not NASA-only sourcing.</li></ul><p>This ADR locks the <strong>approach</strong> (build-time, no runtime third-party fetches) for all four categories. The two unimplemented categories will be added to <code>scripts/fetch-assets.ts</code> in Slice 4 alongside the mission library and mission arc; the script&#39;s structure (per-category async function, fail-fast on individual asset, written to <code>static/</code>) is the contract for those additions.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>Build-time resolution eliminates all runtime third-party dependencies. The app works fully offline after first load. Images are served from the application&#39;s own CDN — faster for users than fetching from NASA or Wikimedia. Rate limits apply at build time (rare, recoverable) not at user time (frequent, user-facing). The build scripts are owned code — no third-party proxy service required.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>Runtime proxy (owned)</strong> — a GitHub Actions job could serve as a proxy at runtime via a worker. Adds operational complexity; build-time is simpler and more robust.</li><li><strong>Third-party image CDN</strong> — Cloudinary, Imgix etc.; introduces third-party dependency; rejected.</li><li><strong>Keep external URLs</strong> — simplest; brittle; fails offline; rejected.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: fully offline-capable; no runtime third-party dependencies; faster image loading; no rate limit risk for users. Negative: build takes longer (asset fetch adds ~2min); weekly rebuild needed for fresh mission imagery; storage in repo increases (logos, textures ~5MB; mission images depend on count/size — managed via Git LFS if needed).</p><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><p><code>scripts/fetch-assets.ts</code> — runs in CI before <code>npm run build</code> (executed via <code>npx tsx</code>). NASA Images API key in GitHub Actions secret. Graceful fallback: if NASA API fails for a mission, placeholder image used. Git LFS for images if size becomes a concern.</p>',17)])])}const h=t(s,[["render",r]]);export{p as __pageData,h as default};
